class Solution:
    def addSpaces(self, s, spaces):
        parts = []
        prev = 0
        for pos in spaces:
            parts.append(s[prev:pos])
            parts.append(' ')
            prev = pos
        parts.append(s[prev:])
        return ''.join(parts)

