var addSpaces = function(s, spaces) {
    const parts = [];
    let prev = 0;
    for (const pos of spaces) {
        parts.push(s.slice(prev, pos));
        parts.push(' ');
        prev = pos;
    }
    parts.push(s.slice(prev));
    return parts.join('');
};
